UPDATE MSF_REQUEST_SVC_CHG SET
    AMD_DT  = NOW(),
    PROC_CD = #{procCd, jdbcType=VARCHAR}
    , OPEN_NO = #{openNo}
WHERE REQUEST_KEY = #{requestKey}
